INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Compute orchestration (Nova)$q$, $q$Provisions and manages virtual machine instances across a pool of hypervisor nodes, including scheduling, scaling, and live migration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Software-defined networking (Neutron)$q$, $q$Gives tenants their own virtual networks, routers, load balancers, firewalls, and floating IPs, independent of the underlying physical network.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Block and object storage (Cinder and Swift)$q$, $q$Cinder provides persistent block storage volumes for instances; Swift provides highly durable, API-driven object storage similar to Amazon S3.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Identity and access management (Keystone)$q$, $q$Centralized authentication, multi-tenancy, and role-based access control shared across every OpenStack service.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Bare-metal provisioning (Ironic)$q$, $q$Provisions physical servers using the same workflow as virtual machines, useful for high-performance and GPU/AI workloads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Orchestration and automation (Heat)$q$, $q$Template-driven infrastructure-as-code for defining and auto-scaling multi-resource application stacks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Web dashboard (Horizon)$q$, $q$A self-service web UI for administrators and tenants to manage instances, networks, storage, and images without using the CLI or API directly.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Fully open source with no licensing fees, and no vendor lock-in.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Highly modular, so deployments can be scaled from a small lab to a telecom-grade, multi-region cloud.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Backed by a mature governance model and a large, active contributor and vendor ecosystem.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Gives organizations full control over data residency and hardware, which matters for regulated industries.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Proven at massive scale in production by telecoms, research institutions, and public clouds.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Steep learning curve and significant operational overhead to deploy and maintain compared to public cloud.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Requires dedicated infrastructure engineering staff; total cost of ownership can exceed public cloud for smaller workloads.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Upgrades between releases can be complex, especially for heavily customized deployments.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Feature parity and documentation quality vary across the many optional sub-projects.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Smaller ecosystem of third-party tools and integrations compared to AWS or Azure.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Is OpenStack free to use?$q$, $q$Yes. OpenStack's source code is free under the Apache 2.0 license. Costs come from the hardware you run it on and any optional commercial support or managed distribution you purchase.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Who maintains OpenStack today?$q$, $q$OpenStack is governed by the OpenInfra Foundation, which became part of the Linux Foundation in March 2025. Development is driven by a global community of individual contributors and member companies.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Is OpenStack the same as Kubernetes?$q$, $q$No. OpenStack is an IaaS platform that manages virtual machines, storage, and networking. Kubernetes orchestrates containers. The two are often deployed together, with OpenStack providing the underlying infrastructure for a Kubernetes cluster.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$What companies use OpenStack in production?$q$, $q$OpenStack powers infrastructure at telecoms (for NFV and 5G core networks), research organizations such as CERN, public sector agencies, and large enterprises that need a self-operated, AWS-like private cloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$How does OpenStack compare to VMware?$q$, $q$VMware is a proprietary, license-based virtualization and private cloud suite, while OpenStack is open source and free to license. OpenStack generally requires more in-house expertise but avoids VMware's licensing costs and lock-in.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Can I get commercial support for OpenStack?$q$, $q$Yes. Vendors including Red Hat, Canonical, Mirantis, VEXXHOST, and Rackspace offer supported distributions and managed OpenStack services with custom pricing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$What programming language is OpenStack written in?$q$, $q$OpenStack's core services are written primarily in Python, with REST APIs used for inter-service and external communication.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Telecom NFV and 5G infrastructure$q$, $q$Telecom operators use OpenStack as the virtualization layer for Network Functions Virtualization, running 5G core and edge network functions on self-operated infrastructure.$q$, $q$Telecom operators and network engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Research and academic private clouds$q$, $q$Universities and research institutions such as CERN run OpenStack to give scientists self-service compute and storage for large-scale data processing without relying on public cloud spend.$q$, $q$Research institutions and universities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Enterprise private and hybrid cloud$q$, $q$Enterprises with data-sovereignty, compliance, or cost-control requirements deploy OpenStack to offer AWS-like self-service provisioning on their own data center hardware.$q$, $q$Enterprise IT and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to all OpenStack services and source code","Community documentation and mailing lists","Twice-yearly coordinated releases","Requires in-house deployment and support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$Vendor-Supported Distribution$q$, $q$Custom$q$, $q$Quoted per deployment$q$, NULL, $q$["Packaged, tested OpenStack distribution","Vendor support contracts and SLAs","Managed upgrade paths","Available from Red Hat, Canonical, Mirantis, VEXXHOST, and others"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenStack is a modular, open-source cloud operating system that turns pools of physical compute, storage, and networking hardware into a self-service Infrastructure-as-a-Service (IaaS) cloud. Rather than shipping as one monolithic product, it is a collection of independent but interoperable services that administrators combine based on what capabilities they need.$q$, $q$Originally created in 2010 by Rackspace and NASA, OpenStack is now stewarded by the OpenInfra Foundation, a nonprofit that became part of the Linux Foundation in 2025. Thousands of individual contributors and hundreds of member organizations, including major cloud vendors, telecoms, and research institutions, continue to develop the project on a roughly twice-yearly release cadence.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, OpenStack provides compute orchestration through Nova, software-defined networking through Neutron, and both block and object storage through Cinder and Swift. Keystone unifies identity and authentication across every service, while Glance manages virtual machine images and Horizon offers a web-based dashboard for administrators and tenants alike.$q$, $q$Beyond the core, optional services extend OpenStack into bare-metal provisioning (Ironic), orchestration and auto-scaling (Heat), container-native workloads, and telecom-grade networking for NFV use cases. This a-la-carte architecture is what lets a small research lab run a minimal deployment while a telecom operator runs a massive multi-region cloud on the same underlying platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8739782d-56c1-4efc-a3ac-3d0c9d531296', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenStack itself carries no license cost; the software is free to download, deploy, and modify under the Apache 2.0 license. The real cost of running OpenStack comes from hardware, staff time, and optional commercial support.$q$, $q$Most organizations either self-host and self-support OpenStack with in-house engineers, or purchase a supported distribution or managed-OpenStack offering from vendors such as Red Hat, Canonical, Mirantis, or VEXXHOST, whose pricing is typically custom and quoted per deployment size and support tier.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Community-editable map data$q$, $q$Any registered user can add or correct map features using the iD or JOSM editors, with full version history for every change.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Open Database License (ODbL)$q$, $q$Map data can be freely used, modified, and redistributed for any purpose, including commercial, as long as attribution is given and derivative databases stay open.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Overpass API and data extracts$q$, $q$Developers can query specific feature types in a region via the Overpass API or download full regional extracts from mirrors like Geofabrik.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Global, granular coverage$q$, $q$Covers roads, trails, buildings, land use, points of interest, and administrative boundaries down to a very local level, especially strong in areas mapped by active local communities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Humanitarian mapping (HOT)$q$, $q$The Humanitarian OpenStreetMap Team coordinates volunteers to rapidly map disaster zones and underserved regions to support relief organizations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Third-party tile, routing, and geocoding services$q$, $q$An ecosystem of providers (Mapbox, MapTiler, OSRM, GraphHopper, Nominatim) build hosted maps, routing, and address search on top of the open OSM dataset.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Map data is free to use commercially with no per-request licensing fees, only attribution.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Extremely detailed and current in areas with active local mapping communities.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Fully transparent and auditable data, with no single company controlling what's shown.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Large open-source ecosystem of routing, geocoding, and rendering tools built on top of it.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Not subject to a single vendor's pricing changes or API shutdowns.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Data quality and completeness vary significantly by region depending on volunteer activity.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$No official customer support; help comes from community forums, mailing lists, and wikis.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Attribution and ODbL share-alike requirements can be a compliance burden for some commercial products.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Raw data requires technical work (rendering, hosting, indexing) to turn into a usable map product.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Editing conventions and tagging schemes have a learning curve for new contributors.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Is OpenStreetMap free to use?$q$, $q$Yes. OSM's map data is free to download, use, and modify, including for commercial products, under the Open Database License, which requires attribution.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Who owns OpenStreetMap?$q$, $q$No single company owns OSM. The data belongs collectively to its contributors, while the OpenStreetMap Foundation, a UK nonprofit, owns and operates the underlying infrastructure and holds the license on the community's behalf.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$How is OpenStreetMap different from Google Maps?$q$, $q$OpenStreetMap's underlying data is open, editable, and free to use commercially with attribution, while Google Maps data is proprietary and access is metered through paid API usage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Who edits OpenStreetMap?$q$, $q$Millions of registered volunteers worldwide edit OSM using tools like the iD web editor or the JOSM desktop editor, sourcing changes from GPS traces, imagery, and local surveys.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Can I use OpenStreetMap data in a commercial app?$q$, $q$Yes, as long as you comply with the Open Database License, which primarily requires giving appropriate attribution to OpenStreetMap contributors.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$What is the Humanitarian OpenStreetMap Team?$q$, $q$HOT is a nonprofit that coordinates volunteer mapping efforts, often rapidly mapping disaster-affected or under-mapped regions to support humanitarian and relief organizations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Do I need to pay to display OpenStreetMap tiles on my website?$q$, $q$Light use of the public openstreetmap.org tile servers is free, but heavy commercial traffic is expected to use a paid third-party tile provider such as Mapbox or MapTiler instead.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Mobile and web app mapping$q$, $q$Developers embed OSM-based maps, geocoding, and routing into apps without per-request licensing fees, often via a commercial tile provider built on OSM data.$q$, $q$App and web developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Disaster response and humanitarian aid$q$, $q$Volunteer mapping communities rapidly survey and map crisis-affected regions to give relief organizations accurate, up-to-date geographic data.$q$, $q$Humanitarian and relief organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$GIS research and civic technology$q$, $q$Researchers, urban planners, and civic-tech projects use OSM's open, inspectable data for analysis and public-facing map tools where data transparency matters.$q$, $q$Researchers, urban planners, and civic-tech teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Open Data (ODbL)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to the global OSM dataset","Free for commercial and non-commercial use with attribution","Downloadable extracts and Overpass API access","Community editing tools (iD, JOSM)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$Third-Party Hosted Tiles/Routing$q$, $q$Custom$q$, $q$Usage-based, varies by provider$q$, NULL, $q$["Hosted map tiles and styling","Geocoding and routing APIs built on OSM data","SLAs and commercial support","Offered independently by providers like Mapbox, MapTiler, and Geofabrik"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenStreetMap is a free, editable database of the world's geography, built entirely by volunteer contributors and released under an open data license. It covers roads, buildings, land use, points of interest, footpaths, and countless other geographic features, all sourced from GPS traces, imagery, surveys, and local knowledge.$q$, $q$The project is stewarded by the OpenStreetMap Foundation, a UK nonprofit, which owns the servers and infrastructure and holds the data license on behalf of the community, but does not control or own the content itself; that belongs collectively to its contributors under the Open Database License.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Contributors edit the map using the browser-based iD editor for quick changes or the more powerful desktop JOSM editor for detailed mapping work, with every edit versioned and attributable like a wiki. The Overpass API and regular data extracts (via providers like Geofabrik) let developers query or download the full dataset for any region.$q$, $q$Because the raw data is open, a broad ecosystem of tools is built on top of it, including custom map styles and tile rendering (OSM Carto and others), routing engines such as OSRM and GraphHopper, and geocoding services, giving developers a full mapping stack without relying on a single proprietary vendor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57200a8f-f3cf-4f52-8aed-098c07fbd667', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenStreetMap's data is free to download and use, including for commercial products, under the ODbL, which requires attribution and that derivative databases remain similarly open.$q$, $q$The Foundation does not charge for map data or the main openstreetmap.org tiles for light usage, but heavy commercial use of the public tile servers is discouraged; instead, most production applications pay third-party providers such as Mapbox, MapTiler, or Geofabrik for hosted tiles, geocoding, and routing built on OSM data, with pricing set independently by each provider.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$GuestCenter reservation and table management$q$, $q$A restaurant-facing system for managing bookings, table assignments, and floor plans in real time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Guest CRM and dining history$q$, $q$Tracks guest preferences, visit history, spend, and special occasions to help restaurants personalize service and target repeat business.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Waitlist and walk-in management$q$, $q$Digitally manages walk-in queues and quoted wait times alongside standard reservations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Diner mobile app and loyalty program$q$, $q$A free consumer app for searching, booking, and reviewing restaurants, with OpenTable Dining Points earned on qualifying reservations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Network marketing and discovery$q$, $q$Restaurant listings surface across OpenTable's site, app, and partner placements to attract new diners.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$POS and payment integrations$q$, $q$Connects with point-of-sale systems and supports deposits and prepaid experiences for high-demand bookings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Review collection$q$, $q$Automatically prompts diners to leave verified reviews after a completed reservation.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Largest and most widely recognized restaurant reservation network, driving significant diner discovery traffic.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Free for diners with no booking fees on the consumer side.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Mature, full-featured guest CRM and table-management tooling on higher-tier plans.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Backed by Booking Holdings, giving it financial stability and distribution muscle.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Well-established integrations with major POS and payment providers.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Per-cover fees on Core and Pro plans can add up quickly for high-volume restaurants.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$2026 service fee on deposits and prepaid experiences adds another cost layer.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Lower-tier Basic plan has limited CRM and marketing functionality.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Restaurants compete for visibility within the same network as nearby competitors.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Newer competitors like Resy and Tock offer more flexible pricing models for some restaurant types.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Is OpenTable free for diners?$q$, $q$Yes, searching for and booking a table on OpenTable is completely free for diners; OpenTable charges restaurants, not guests, for reservations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$How much does OpenTable cost for restaurants?$q$, $q$Restaurants choose from three plans: Basic at $149/month, Core at $299/month plus $1 per network cover, and Pro at $499/month plus $1 per network cover; a 2% service fee also applies to deposits and prepaid experiences as of 2026.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Who owns OpenTable?$q$, $q$OpenTable has been a subsidiary of Booking Holdings (NASDAQ: BKNG) since it was acquired from The Priceline Group in 2014 for about $2.6 billion.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$When was OpenTable founded?$q$, $q$OpenTable was founded on July 2, 1998, in San Francisco by Chuck Templeton, Sid Gorham, and Eric Moe.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$What are the main alternatives to OpenTable?$q$, $q$Common alternatives include Resy and Tock (both owned by American Express), Yelp Guest Manager, SevenRooms, and Toast Tables, each with different pricing models and target restaurant segments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$What is OpenTable Dining Points?$q$, $q$It is OpenTable's diner loyalty program, where guests earn points for completing eligible reservations that can be redeemed for dining credit.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Does OpenTable work outside the United States?$q$, $q$Yes, OpenTable operates internationally in markets including the UK, Germany, Mexico, and Japan, though restaurant density and plan availability vary by market.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Diner table booking$q$, $q$Consumers search real-time availability and book tables instantly at nearby or destination restaurants without calling ahead.$q$, $q$Restaurant diners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Independent restaurant reservation and waitlist management$q$, $q$Single-location restaurants use OpenTable's Basic or Core plans to manage online bookings, walk-in queues, and table assignments.$q$, $q$Independent restaurant owners and hosts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Multi-location guest relationship management$q$, $q$Restaurant groups and hospitality brands use Pro-tier GuestCenter CRM to unify guest profiles and marketing across multiple venues.$q$, $q$Restaurant groups and hotel F&amp;B operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Diner App$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Search real-time restaurant availability","Instant online booking","OpenTable Dining Points loyalty program","Reviews and personalized recommendations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Basic$q$, $q$$149/month$q$, $q$Monthly$q$, NULL, $q$["Core reservation and table management","Standard network listing","No per-cover fee"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Core$q$, $q$$299/month + $1 per network cover$q$, $q$Monthly$q$, NULL, $q$["Everything in Basic","Enhanced guest CRM","Free website-direct reservations","Waitlist management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$Pro$q$, $q$$499/month + $1 per network cover$q$, $q$Monthly$q$, NULL, $q$["Everything in Core","Advanced marketing and analytics","Deeper CRM and guest segmentation","Priority network placement"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenTable is a two-sided marketplace: a free consumer app and website for diners to find and book restaurant tables, and a paid subscription platform for restaurants to manage reservations, waitlists, and guest relationships.$q$, $q$Founded in 1998 and acquired by Booking Holdings in 2014, OpenTable operates one of the largest restaurant reservation networks in the world, spanning more than 60,000 restaurants across dozens of countries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$For diners, OpenTable offers real-time table availability search, instant online booking, a loyalty points program, and personalized restaurant recommendations. For restaurants, the GuestCenter platform combines a reservation book, table and floor-plan management, a waitlist and walk-in queue, and a guest CRM that tracks dining history, preferences, and special occasions.$q$, $q$Restaurants also get access to marketing placement across OpenTable's network and mobile apps, automated guest review collection, and integrations with point-of-sale and payment systems, which together are designed to both fill tables and deepen repeat-guest relationships.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae9d7434-92d8-4d57-91cd-e0572dbd91d6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Diners never pay to search for or book a table on OpenTable; the platform monetizes exclusively on the restaurant side.$q$, $q$Restaurants choose between three monthly plans: Basic ($149/month, flat), Core ($299/month plus $1 per online 'network' cover), and Pro ($499/month plus $1 per network cover, with deeper CRM and marketing tools). As of early 2026, OpenTable also applies a 2% service fee on deposits and prepaid dining experiences booked through the platform.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Multi-language SDKs$q$, $q$Official instrumentation libraries for Java, Python, Go, Node.js, .NET, Ruby, PHP, C++, Rust, Swift, Erlang/Elixir, and more.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Auto-instrumentation$q$, $q$Agents that instrument popular frameworks and libraries automatically with minimal code changes, especially mature for Java and .NET.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$OpenTelemetry Collector$q$, $q$A standalone, vendor-agnostic pipeline for receiving, processing, batching, and exporting telemetry to one or more backends.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Unified traces, metrics, and logs$q$, $q$A single instrumentation model covers all three telemetry signal types instead of requiring separate libraries for each.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$OTLP protocol$q$, $q$A standardized wire protocol supported natively by nearly every major observability backend, avoiding custom export formats.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Semantic conventions$q$, $q$Standardized naming and attribute schemas so telemetry from different services and languages stays consistent and comparable.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Backend portability$q$, $q$Instrument once, then send data to Datadog, New Relic, Dynatrace, Grafana, Honeycomb, or a self-hosted stack without re-instrumenting.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Completely free, open source, and vendor-neutral, avoiding lock-in to a single observability vendor.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$CNCF Graduated status signals production maturity and long-term project stability.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Broad language and framework coverage with strong auto-instrumentation for major stacks.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Now supported natively by nearly every major APM and observability backend.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Backed by a large, active community and contributions from major cloud and observability vendors.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Does not include a storage backend, dashboard, or alerting; you must pair it with a separate observability tool.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Instrumentation quality and auto-instrumentation maturity still vary by language and framework.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Collector configuration and pipeline tuning can be complex for advanced, multi-backend setups.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Semantic conventions have evolved over time, occasionally requiring migration work for existing instrumentation.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Steeper initial learning curve than a single vendor's proprietary, all-in-one instrumentation agent.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Is OpenTelemetry free?$q$, $q$Yes. OpenTelemetry is fully open source under the Apache 2.0 license with no cost to use. You only pay for whatever backend you choose to store and analyze the telemetry it produces.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Who created OpenTelemetry?$q$, $q$OpenTelemetry was formed in 2019 by merging two earlier projects, OpenTracing and OpenCensus, under the Cloud Native Computing Foundation (CNCF).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Does OpenTelemetry replace tools like Datadog or New Relic?$q$, $q$No. OpenTelemetry standardizes how telemetry is generated and transmitted; it still needs a backend like Datadog, New Relic, Grafana, or an open-source stack to store, visualize, and alert on the data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$What is the OpenTelemetry Collector?$q$, $q$It is a vendor-agnostic service that receives telemetry from your applications, processes or batches it, and exports it to one or more observability backends, decoupling instrumentation from any specific vendor.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$What languages does OpenTelemetry support?$q$, $q$OpenTelemetry provides official SDKs for more than a dozen languages, including Java, Python, Go, JavaScript/Node.js, .NET, Ruby, PHP, C++, Rust, and Erlang/Elixir.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Is OpenTelemetry production-ready?$q$, $q$Yes. CNCF announced OpenTelemetry's graduation, its highest maturity status, in May 2026, reflecting widespread production adoption across the industry.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$What is the difference between OpenTracing, OpenCensus, and OpenTelemetry?$q$, $q$OpenTracing and OpenCensus were two earlier, competing telemetry standards; they merged in 2019 to form OpenTelemetry, which is now the actively maintained successor to both.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Microservices instrumentation$q$, $q$Engineering teams instrument distributed, polyglot microservices once with OpenTelemetry to get consistent traces and metrics across every service.$q$, $q$SRE and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Vendor-neutral observability strategy$q$, $q$Organizations standardize on OTel to avoid rewriting instrumentation if they switch or evaluate observability backends over time.$q$, $q$Enterprises evaluating or migrating observability vendors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Multi-backend telemetry routing$q$, $q$Teams use the OpenTelemetry Collector to fan the same telemetry out to multiple destinations, such as a cost-effective long-term store and a real-time alerting tool.$q$, $q$DevOps and observability engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to all SDKs, the Collector, and specifications","Apache 2.0 licensed","Community and CNCF governance","No usage limits or paid tiers"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenTelemetry is an open-source, vendor-neutral standard for instrumenting applications to produce traces, metrics, and logs. It exists to solve fragmentation: before OTel, teams often had to choose between multiple incompatible tracing and metrics libraries, each tied to a specific observability vendor.$q$, $q$Formed in 2019 from the merger of OpenTracing and OpenCensus, OpenTelemetry is hosted by the Cloud Native Computing Foundation (CNCF) and reached CNCF's Graduated status in May 2026, its highest level of project maturity, reserved for widely adopted, production-proven projects.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenTelemetry provides language SDKs and auto-instrumentation agents for more than a dozen popular languages, standardized semantic conventions for naming telemetry data consistently across services, and the OpenTelemetry Collector, a configurable pipeline that can receive, batch, transform, and export telemetry to one or more backends.$q$, $q$Because everything speaks a common protocol (OTLP), teams can capture traces, metrics, and logs once and route them to any compatible backend, switch backends without re-instrumenting code, or fan out the same telemetry to multiple destinations at once, such as a security data lake and an APM tool simultaneously.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('567932b8-eb63-435b-a35e-b252afd5a120', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenTelemetry itself is entirely free and open source, licensed under Apache 2.0, with no paid tier, seat licenses, or usage limits imposed by the project.$q$, $q$The cost that organizations actually incur comes from the observability backend they choose to send OTel data to, whether that is a commercial APM vendor billed by ingested data volume or hosts, or infrastructure costs for self-hosting an open-source stack like Prometheus, Grafana, and Jaeger.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Unlimited-user free tier$q$, $q$The Free Plan supports an unlimited number of employees and departments at no cost, unusual for the time-tracking category.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$GPS and geofenced clock-in$q$, $q$Verifies employee location at clock-in and clock-out to help prevent time theft and buddy punching for field or multi-site teams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Facial recognition clock-in$q$, $q$Optional biometric verification adds an extra layer of identity confirmation at the time clock.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$PTO and accrual tracking$q$, $q$Tracks vacation, sick leave, and other paid-time-off accruals and balances automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Shift scheduling$q$, $q$Lets managers build and publish employee shift schedules alongside time tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Job and project cost tracking$q$, $q$Allows employees to log hours against specific jobs, clients, or projects for cost and billing analysis.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Offline clock-in support$q$, $q$Employees can clock in without an internet connection, with entries syncing automatically once connectivity is restored.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Free plan supports unlimited employees, which is rare among time-tracking competitors that charge per seat.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Paid plan is inexpensive relative to per-user competitors, especially for larger teams.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Supports multiple clock-in methods, including GPS, facial recognition, and offline mode.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Includes job costing and PTO accrual tracking typically reserved for pricier platforms.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Nonprofit-friendly pricing and a free 'Sponsor Link' option for cost-conscious organizations.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Free plan loses PDF/Excel report export after the initial 30-day trial period.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Company does not publicly disclose a physical headquarters or leadership team, which may concern due-diligence-conscious buyers.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Interface and design feel dated compared to newer, VC-backed time-tracking competitors.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Smaller integration ecosystem with payroll and HR platforms than larger competitors like TSheets/QuickBooks Time or Deputy.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Customer support is phone/email based with limited hours rather than 24/7 live chat.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Is OpenTimeClock really free?$q$, $q$Yes, the Free Plan supports unlimited employees at no cost. The main limitation is that PDF/Excel report exports are only free for the first 30 days, after which they require the Paid Plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$How much does the OpenTimeClock Paid Plan cost?$q$, $q$The Paid Plan is $39/month billed monthly, or $399/year billed annually (about $33.25/month), and covers unlimited users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Does OpenTimeClock support GPS tracking?$q$, $q$Yes, it supports GPS-based clock-in verification and geofencing so managers can confirm employees clocked in from an approved location.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Can nonprofits get a discount on OpenTimeClock?$q$, $q$OpenTimeClock offers reduced or free access to qualifying nonprofit organizations (NPOs) under its NPO program.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$What is the Sponsor Link plan?$q$, $q$It lets an organization unlock Paid Plan features for free by placing a text link to Open Time Clock or 'Time Clock Software' on their website's homepage.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Does OpenTimeClock work offline?$q$, $q$Yes, employees can clock in without an internet connection and entries will sync automatically once the device reconnects.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$How long has OpenTimeClock been in business?$q$, $q$The company states it has been in business since 1997, though its current web-based product line has evolved considerably since then.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Small business payroll-ready time tracking$q$, $q$Small businesses use the free or paid plan to track hourly employee attendance and export data for payroll processing.$q$, $q$Small business owners and office managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Multi-site and field-service workforce tracking$q$, $q$Companies with mobile or multi-location employees use GPS geofencing and offline clock-in to verify attendance away from a central office.$q$, $q$Construction, field service, and multi-location businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Nonprofit and school attendance tracking$q$, $q$Nonprofits and schools with large or fluctuating headcounts use the unlimited-user free tier to track staff or volunteer hours without per-seat costs.$q$, $q$Nonprofits, schools, and volunteer-heavy organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Free Plan$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited employees and departments","Web and mobile clock-in","On-screen and CSV reporting","PDF/Excel export free for first 30 days"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Paid Plan (Monthly)$q$, $q$$39/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited users","PDF/Excel report export","Shift scheduling and PTO accrual","GPS tracking and job costing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Paid Plan (Yearly)$q$, $q$$399/year (~$33.25/month)$q$, $q$Annual$q$, NULL, $q$["Same features as monthly Paid Plan","Discounted annual rate"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$Sponsor Link$q$, $q$Free (in exchange for a homepage link)$q$, $q$N/A$q$, NULL, $q$["All Paid Plan features","Requires a text link to Open Time Clock on your homepage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenTimeClock is a web-based time and attendance system built for small and mid-sized organizations that need to track employee hours, breaks, and paid time off without paying per-user fees. It has operated since 1997 and runs on Amazon Web Services infrastructure.$q$, $q$Its standout feature is an unlimited-user free tier, a rarity in the time-tracking category where most competitors charge per employee per month. Paid upgrades add reporting exports and advanced scheduling, approval, and job-costing features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Employees can clock in and out from a web browser, mobile app, or a shared kiosk device, with optional GPS geofencing and facial recognition to verify identity and location at clock-in. Managers get timesheet approval workflows, PTO and vacation accrual tracking, shift scheduling, and job or project cost tracking for billing purposes.$q$, $q$Reporting tools support payroll processing with exportable timesheets, and the system offers offline clock-in support for locations with unreliable internet, syncing entries once connectivity returns.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c4f3d77-298c-424f-a26d-6c21dd92ceda', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free Plan includes unlimited employees and departments; its main restriction is that PDF/Excel report exports require a paid upgrade after an initial 30-day trial window, though CSV and on-screen reporting remain available indefinitely.$q$, $q$The Paid Plan costs $39/month, or $399/year when billed annually (about $33.25/month), also for unlimited users, and unlocks report exports, shift scheduling, PTO accrual, GPS tracking, and job costing. A Sponsor Link option lets organizations get Paid Plan features free in exchange for a homepage text-link back to Open Time Clock, and discounted access is generally available to qualifying nonprofits.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Multimodal itinerary planning$q$, $q$Computes trip options combining public transit, walking, cycling, and driving in a single routing engine.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$GTFS and GTFS-Realtime support$q$, $q$Ingests standard transit schedule data and applies real-time delay and service-change updates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$NeTEx data support$q$, $q$Supports the EU-standard NeTEx transit data format, enabling regulatory compliance for European deployments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$OTP2 round-based routing engine$q$, $q$A high-performance transit routing core, inspired by the R5 algorithm, introduced in the 2020 OTP2 release for faster, more scalable queries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$REST and GraphQL APIs$q$, $q$Exposes standard APIs for integrating trip-planning results into web and mobile applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Accessibility-aware routing$q$, $q$Supports wheelchair-accessible itinerary options for riders with mobility needs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Self-hosted deployment$q$, $q$Runs entirely on an agency's own infrastructure, giving full control over data and uptime rather than relying on a third-party API.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Free and open source with no licensing fees, ideal for public agencies with limited budgets.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Proven at scale across many transit agencies and national deployments worldwide.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Supports both GTFS and the EU's NeTEx standard, useful for both American and European agencies.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$OTP2's routing engine delivers strong performance even for large, complex transit networks.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Governed by an open, multi-organization process rather than a single vendor's roadmap.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Requires in-house or contracted engineering expertise to deploy, configure, and maintain.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$No official vendor support; help comes from community channels and paid consultancies.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Data preparation (clean GTFS/OSM feeds) is a significant, ongoing operational burden.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Less polished out-of-the-box UI compared to consumer-facing proprietary map/transit apps.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Smaller ecosystem of turnkey hosting options compared to commercial routing APIs.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Is OpenTripPlanner free to use?$q$, $q$Yes, OpenTripPlanner is open source under the LGPL license and free to download, deploy, and modify. Costs come from hosting, data preparation, and any optional paid support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Who created OpenTripPlanner?$q$, $q$It originated in 2009 through a project funded by TriMet, Portland's transit agency, which brought together the developers of several earlier open-source transit routing tools to build a unified successor.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$What data does OpenTripPlanner use?$q$, $q$It uses GTFS (and GTFS-Realtime for live updates) or NeTEx for transit schedules, combined with OpenStreetMap data for streets, paths, and cycling infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$What is OTP2?$q$, $q$OTP2 is a major 2020 rewrite of OpenTripPlanner's transit routing engine, inspired by the R5 algorithm, that significantly improved performance and added support for the EU's NeTEx data standard.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Who uses OpenTripPlanner?$q$, $q$Public transit agencies, regional transportation authorities, and mobility developers use OTP, including TriMet in Portland and national deployments such as Entur in Norway.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Can I get commercial support for OpenTripPlanner?$q$, $q$Yes, several firms including Conveyal and Cambridge Systematics offer paid hosting, integration, and support services built around OTP, typically quoted per project.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Does OpenTripPlanner support real-time transit updates?$q$, $q$Yes, it can ingest GTFS-Realtime feeds to factor in live delays, cancellations, and service changes when computing itineraries.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Transit agency trip planners$q$, $q$Transit agencies deploy OTP to power the official rider-facing trip planner on their website or app, covering their own service area.$q$, $q$Public transit agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Mobility-as-a-service (MaaS) platforms$q$, $q$Cities and mobility startups integrate OTP's multimodal routing to combine transit with bikeshare, scooters, and other modes in one planning experience.$q$, $q$MaaS platforms and city mobility programs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Transportation research and analysis$q$, $q$Researchers and consultancies use OTP's routing engine to model accessibility, travel times, and network scenarios for planning studies.$q$, $q$Transportation researchers and planning consultancies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full multimodal routing engine","GTFS, GTFS-Realtime, and NeTEx support","REST and GraphQL APIs","Requires self-hosting and data preparation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$Commercial Hosting/Support$q$, $q$Custom$q$, $q$Quoted per project$q$, NULL, $q$["Managed hosting and deployment","Integration and customization services","Available from firms such as Conveyal and Cambridge Systematics"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenTripPlanner is an open-source routing engine that computes multimodal trip itineraries, combining public transit schedules with walking, cycling, and driving networks to answer 'how do I get from A to B' queries.$q$, $q$It began in 2009 as a TriMet-funded effort to unify several competing open-source transit routing tools into a single successor project, and has since grown into a globally used platform maintained by an international community of transit agencies and developers rather than any single company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OTP ingests GTFS transit schedule data and OpenStreetMap street/path data to build a routable graph, then computes itineraries across transit, walking, biking, and driving, including real-time updates via GTFS-Realtime feeds for delays and service changes. The OTP2 release introduced a round-based transit routing engine inspired by R5 for much faster performance, along with support for the EU's NeTEx data standard.$q$, $q$The engine exposes REST and GraphQL APIs for integration into web and mobile trip-planning applications, supports accessibility-aware routing such as wheelchair-accessible itineraries, and can calculate fares for supported transit systems, all while being fully self-hostable on an agency's own infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f8129e3-98ab-4d78-94b2-3a35a0efb279', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenTripPlanner is free and open source under the LGPL license, so there is no software cost to download, deploy, or modify it.$q$, $q$Real-world costs come from server hosting, preparing and maintaining GTFS/NeTEx and OSM data feeds, and any optional commercial integration, hosting, or support services purchased from firms in the OTP ecosystem, which are typically quoted on a custom basis.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Transport network building$q$, $q$Design and operate rail, road, sea, and air transport routes connecting towns and industries across a large simulated map.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$NewGRF mod support$q$, $q$A rich modding format that lets the community add custom vehicles, graphics, scenarios, and gameplay mechanics.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Free replacement asset packs$q$, $q$OpenGFX, OpenSFX, and OpenMSX provide free graphics, sound, and music, so the game can be played without the original commercial title.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Custom AI and game scripts$q$, $q$Players can script AI opponents or automate parts of their own gameplay using OpenTTD's scripting API.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Multiplayer support$q$, $q$Play cooperatively or competitively with others over LAN or the internet.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Cross-platform availability$q$, $q$Native ports for Windows, macOS, Linux, and BSD keep the game accessible across operating systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Large, customizable maps$q$, $q$Procedurally generated maps far larger and more varied than the original game's, with extensive scenario editing tools.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Completely free with no purchase price or in-game monetization.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Actively developed and updated for over two decades by a dedicated volunteer community.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Deep modding ecosystem (NewGRF) that keeps adding new content years after release.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Runs natively on Windows, macOS, Linux, and BSD.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Can be played entirely with free assets, without needing the original commercial game.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Dated core gameplay loop and UI conventions inherited from a 1995 game may feel unfamiliar to modern strategy gamers.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Steep learning curve for new players unfamiliar with classic tycoon-style transport games.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$No official marketing or storefront presence, so discoverability relies on word of mouth and community channels.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Setting up internet multiplayer or custom mod packs can require technical know-how.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$No official support channel; help comes from community forums and wikis rather than paid support.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Is OpenTTD free?$q$, $q$Yes, OpenTTD is completely free to download and play, with no purchase price or in-game purchases.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Do I need to own the original Transport Tycoon Deluxe to play OpenTTD?$q$, $q$No. Free community-made asset packs (OpenGFX, OpenSFX, OpenMSX) provide graphics, sound, and music, so OpenTTD can be played fully without owning the original commercial game.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Who created OpenTTD?$q$, $q$Swedish programmer Ludvig Strigeus began reverse-engineering Transport Tycoon Deluxe in 2003 and released the first version of OpenTTD on March 6, 2004; it has since been maintained by a volunteer open-source community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$What license is OpenTTD released under?$q$, $q$OpenTTD is released under the GNU General Public License version 2 (GPLv2), an open-source license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Does OpenTTD support multiplayer?$q$, $q$Yes, OpenTTD supports both LAN and internet multiplayer, letting players build and compete on shared transport networks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Can I mod OpenTTD?$q$, $q$Yes, OpenTTD has an extensive modding ecosystem based on the NewGRF format, letting the community add custom vehicles, graphics, and scenarios, plus a scripting API for custom AI opponents.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$What platforms does OpenTTD run on?$q$, $q$OpenTTD has native ports for Windows, macOS, Linux, and BSD.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Classic tycoon and simulation gaming$q$, $q$Fans of business simulation and transport-management games play OpenTTD for its deep economic and logistics gameplay.$q$, $q$Strategy and simulation game enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Retro gaming and preservation$q$, $q$Players revisit or discover the classic Transport Tycoon Deluxe experience through a modernized, actively maintained free remake.$q$, $q$Retro gaming enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Modding and scripting hobby projects$q$, $q$Hobbyist developers build custom NewGRF content, scenarios, or AI scripts, contributing to OpenTTD's long-running community ecosystem.$q$, $q$Modders and hobbyist developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$Open Source Game$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full game with no purchase price","Multiplayer support","Access to community mods and asset packs","Cross-platform on Windows, macOS, Linux, and BSD"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenTTD is a free, open-source recreation and expansion of Transport Tycoon Deluxe, the 1995 business simulation game where players design and operate transport networks to move passengers and cargo for profit. It has been developed continuously by a volunteer community since its first release in 2004.$q$, $q$Built by reverse-engineering the original game and rewriting it in C, OpenTTD preserves the addictive core loop of the original while modernizing it with larger maps, scripting, mod support, and cross-platform availability.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Players construct rail lines, roads, shipping routes, and airports to connect towns and industries, managing vehicle fleets, schedules, and finances across a simulated, growing economy. OpenTTD supports custom AI opponents and game scripts, letting players automate or challenge themselves against scripted competitors.$q$, $q$An extensive NewGRF modding ecosystem lets the community add new vehicles, graphics sets, scenarios, and gameplay mechanics, while free asset packs (OpenGFX, OpenSFX, OpenMSX) mean the game can be played fully without owning the original commercial release. It also supports online and LAN multiplayer and runs natively on Windows, macOS, Linux, and BSD.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae510c8a-18ad-492c-8df9-432190e35f9d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OpenTTD is completely free to download and play, with no purchase price, subscription, or in-game monetization of any kind.$q$, $q$The project is funded entirely through voluntary community contributions of time and, occasionally, donations to support server and development infrastructure, rather than any commercial revenue model.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Network vulnerability scanning$q$, $q$Scans hosts and networks for known vulnerabilities, missing patches, and misconfigurations using a continuously updated test feed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Authenticated and unauthenticated scans$q$, $q$Supports both credential-based scans for deeper OS/application-level checks and unauthenticated scans that mimic an external attacker's view.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$CVE and CVSS-based reporting$q$, $q$Findings are mapped to CVE identifiers and scored with CVSS severity to help teams prioritize remediation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Continuously updated vulnerability test (VT) feed$q$, $q$A regularly refreshed feed of vulnerability tests keeps scan coverage current against newly disclosed CVEs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Greenbone Security Assistant web UI$q$, $q$A web-based dashboard for configuring scans, scheduling, and reviewing results without using the command line.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Compliance scanning policies$q$, $q$Pre-built scan configurations aligned with common compliance and hardening benchmarks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$REST/OSP API integration$q$, $q$Allows scan results to be pulled into SIEM platforms, ticketing systems, and other security workflows.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Core scanner is free and fully open source, with no license fee for the community edition.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Backed by Greenbone, a dedicated company actively maintaining and extending the project since 2006.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Broad vulnerability test coverage mapped to CVE and CVSS for standardized prioritization.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$German, GDPR-conscious origin appeals to privacy- and compliance-sensitive European organizations.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Commercial Greenbone tiers are priced below several established proprietary competitors.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Community feed updates slightly later than Greenbone's paid enterprise feed.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Enterprise and Basic tier pricing is not published; buyers must contact sales for a quote.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Setup and tuning can be more involved than some polished commercial-only scanners.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Smaller company size than large competitors like Tenable or Qualys can mean a smaller partner/integration ecosystem.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Scan performance and false-positive rates require ongoing tuning compared to some mature commercial alternatives.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Is OpenVAS free?$q$, $q$Yes, the core OpenVAS scanner and the Greenbone Community Edition are free and open source. Greenbone also sells paid Basic and Enterprise tiers with additional features and faster feed updates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$What is the difference between OpenVAS and Greenbone?$q$, $q$OpenVAS is the open-source vulnerability scanning engine; Greenbone is the German company that develops it and sells commercial products, appliances, and support built around it, branded as Greenbone Vulnerability Management (GVM).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Is OpenVAS a fork of Nessus?$q$, $q$Yes, OpenVAS originated as a fork of the Nessus scanner after Tenable Network Security made Nessus proprietary in October 2005.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Where is Greenbone headquartered?$q$, $q$Greenbone AG is headquartered in Osnabruck, Germany, where it was founded in 2008.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$How does OpenVAS compare to Tenable Nessus?$q$, $q$Both scan for vulnerabilities using CVE/CVSS-based reporting, but OpenVAS's core is open source and free, while Nessus is a proprietary, commercially licensed product; Greenbone's paid tiers compete directly with Nessus's commercial pricing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Does OpenVAS support compliance scanning?$q$, $q$Yes, it includes pre-built scan policies aligned with common compliance and security hardening benchmarks in addition to general vulnerability scanning.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Who should use OpenVAS?$q$, $q$Security teams, penetration testers, and managed security service providers who need CVE/CVSS-based network vulnerability scanning without the licensing cost of a fully proprietary scanner.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Internal network vulnerability assessment$q$, $q$Security teams run regular OpenVAS scans across internal networks to find missing patches and misconfigurations before attackers do.$q$, $q$Internal security and IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Managed security services$q$, $q$MSSPs use OpenVAS or Greenbone's commercial tiers to deliver vulnerability scanning as a service across multiple client environments.$q$, $q$Managed security service providers (MSSPs)$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Compliance and audit scanning$q$, $q$Organizations use OpenVAS's compliance-oriented scan policies to support regulatory audits and security certification requirements.$q$, $q$Compliance and audit teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$OpenVAS/GVM Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source vulnerability scan engine","Community vulnerability test feed","Greenbone Security Assistant web UI","Self-hosted deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$OPENVAS BASIC$q$, $q$Custom$q$, $q$Annual license$q$, NULL, $q$["Licensed appliance/software for small businesses","Faster-updating feed than community edition","Vendor support","Priced below comparable competitor licenses per Greenbone"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$Greenbone Enterprise$q$, $q$Custom$q$, $q$Quoted per deployment$q$, NULL, $q$["Enterprise appliances and feed subscriptions","Advanced reporting and compliance features","Dedicated vendor support and SLAs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenVAS is a free, open-source vulnerability scanner used to find security weaknesses, missing patches, and misconfigurations across networked systems. It began as a fork of the Nessus engine after Nessus went proprietary in 2005, and has been developed since 2006 primarily by the German company Greenbone.$q$, $q$Greenbone, founded in Osnabruck, Germany, in 2008, layers commercial products, appliances, and support on top of the free OpenVAS core, branding the overall framework Greenbone Vulnerability Management (GVM) since 2017, while OpenVAS remains the name of the open-source scan engine at its heart.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OpenVAS scans network targets against a continuously updated feed of vulnerability tests covering thousands of known CVEs, supporting both unauthenticated network scans and authenticated (credentialed) scans that check for missing patches and misconfigurations at the OS and application level. Results are reported with CVE references and CVSS severity scoring to help teams prioritize remediation.$q$, $q$The broader Greenbone Vulnerability Management framework adds a web-based interface (Greenbone Security Assistant), scan scheduling and reporting, compliance-oriented scan policies, and REST/OSP APIs for integrating scan results into SIEM, ticketing, and other security tooling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d037963-f9fb-4d88-bcc4-228a333d83cf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core OpenVAS scanner and the Greenbone Community Edition are free and open source, giving anyone access to vulnerability scanning without a license fee, though the community feed of vulnerability tests updates on a slight delay compared to paid feeds.$q$, $q$Greenbone also sells commercial tiers on top of the open-source core: OPENVAS BASIC is an entry-level licensed product for small businesses priced below comparable competitor tools, while Greenbone Enterprise appliances and enterprise feed subscriptions for larger organizations are quoted individually; exact pricing for both is only available by contacting Greenbone sales.$q$]::text[], 2);
