-- Enrichment marathon batch: OpenStack, OpenStreetMap, OpenTable, OpenTelemetry, OpenTimeClock, OpenTripPlanner, OpenTTD, OpenVAS

-- ── OpenStack ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenStack is a free, open-source cloud computing platform that lets organizations pool compute, storage, and networking resources to build and operate public or private Infrastructure-as-a-Service (IaaS) clouds.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Nonprofit foundation (OpenInfra Foundation, part of the Linux Foundation) with thousands of global contributors$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, United States (OpenInfra Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenStack Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenStack in 2026: what the open-source cloud platform does, how its services fit together, real deployment costs, and how it compares to AWS and VMware.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenStack is a free, open-source cloud computing platform used to build and operate Infrastructure-as-a-Service (IaaS) clouds, both public and private. It launched in July 2010 as a joint project between Rackspace Hosting and NASA, combining Rackspace's Cloud Files object storage platform with NASA's Nebula compute platform; the first release, codenamed 'Austin,' shipped in October 2010. Governance moved to the independent, nonprofit OpenStack Foundation in September 2012, which was renamed the Open Infrastructure Foundation (OpenInfra Foundation) around 2020-2021 to reflect a broader portfolio of adjacent projects including Kata Containers, Zuul, Airship, and StarlingX. In March 2025 the OpenInfra Foundation joined the Linux Foundation as the OpenInfra division, placing OpenStack under the same nonprofit umbrella as Kubernetes. Written primarily in Python and licensed under Apache 2.0, OpenStack is organized as a set of interoperable services rather than a single application: Nova handles compute/VM provisioning, Neutron handles software-defined networking, Cinder and Swift provide block and object storage, Keystone provides identity and access management, Glance manages images, Ironic provisions bare metal, Heat handles orchestration, and Horizon is the web dashboard. Because it is fully open source, there is no license fee to run it; organizations either self-host on their own hardware or buy supported distributions and managed OpenStack services from vendors such as Red Hat, Canonical, Mirantis, VEXXHOST, and Rackspace, which is where most real-world spend occurs. OpenStack's core audience is telecoms building NFV and 5G infrastructure, research institutions and universities (including large deployments like CERN's), government agencies with data-sovereignty requirements, and large enterprises that want AWS- or Azure-style self-service cloud provisioning on infrastructure they control. It differs from a single hypervisor by providing a full multi-tenant cloud operating system, and it differs from Kubernetes by managing virtual machines and infrastructure rather than containers; the two are commonly deployed together, with OpenStack as the IaaS layer under a Kubernetes control plane. Its main competitors and alternatives include proprietary public clouds (AWS, Microsoft Azure, Google Cloud), VMware vSphere/vCloud for private virtualization, and other open-source options such as Apache CloudStack, Proxmox VE, and OpenNebula. As one of the largest and longest-running open-source infrastructure projects, OpenStack remains a default choice for organizations needing a vendor-neutral, self-operated cloud platform at scale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8739782d-56c1-4efc-a3ac-3d0c9d531296';

