-- ── OpenStreetMap ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenStreetMap (OSM) is a free, editable map of the world built and maintained by a global community of volunteer mappers and governed by the nonprofit OpenStreetMap Foundation.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$Nonprofit foundation with a small paid staff; millions of registered volunteer contributors worldwide$q$, company_size),
  headquarters = COALESCE($q$Cambridge, United Kingdom (OpenStreetMap Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenStreetMap Review 2026: Features, Data Licensing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$What OpenStreetMap is, how its open map data and editing tools work, its licensing terms, and how it compares to Google Maps and Mapbox in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenStreetMap (OSM) is a free, collaboratively edited geographic database and map of the world, often described as 'Wikipedia for maps.' It was founded in 2004 by Steve Coast while he was a student at University College London, motivated by the fact that most map data at the time was proprietary and restrictively licensed even in countries like the United Kingdom. The OpenStreetMap Foundation (OSMF), a UK-registered nonprofit headquartered in Cambridge, England, was established in 2006 to own the infrastructure, hold the data license, and support the project's growth; it operates with a small paid staff and is funded by donations, corporate memberships, and sponsorships rather than by selling the map data itself. OSM's underlying data is contributed and edited by millions of registered volunteers using tools like the browser-based iD editor and the more advanced desktop JOSM editor, sourced from GPS traces, aerial and satellite imagery, and local knowledge; edits are tracked with full version history, similar to a wiki. The dataset is released under the Open Database License (ODbL), which allows free use, modification, and redistribution as long as derivative databases remain open and attribution is given. Because the raw data is free, an entire ecosystem of commercial and nonprofit services is built on top of it, including tile-hosting and geocoding providers (Mapbox, MapTiler, Geofabrik, Thunderforest), routing engines (OSRM, GraphHopper, Valhalla), and the humanitarian mapping community (Humanitarian OpenStreetMap Team, or HOT), which mobilizes volunteers to rapidly map disaster and crisis zones for aid organizations. OSM's target audience spans app developers who need map tiles or geocoding without per-request licensing fees, GIS professionals and researchers who need transparent, inspectable geographic data, transit and logistics companies building routing products, and civic-tech and humanitarian organizations. Its main points of differentiation from proprietary alternatives like Google Maps or Apple Maps are that the data is free to use commercially (subject to attribution), fully inspectable and editable by anyone, and not tied to a single corporate provider's terms of service or pricing changes. Competitors and adjacent players include Google Maps Platform, HERE Technologies, TomTom, and Apple Maps on the proprietary side, and commercial OSM-data providers on the open side. Twenty years after launch, OpenStreetMap remains the largest open geographic dataset in the world and a foundational layer for a large share of the world's mapping and navigation software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '57200a8f-f3cf-4f52-8aed-098c07fbd667';

