-- ── OpenTable ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenTable is an online and mobile restaurant reservation and guest-management platform connecting diners with tens of thousands of restaurants worldwide, owned by Booking Holdings.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$149/month for restaurants; free for diners$q$, starting_price),
  founded_year = COALESCE(1998, founded_year),
  company_size = COALESCE($q$Approximately 2,000-2,200 employees (subsidiary of Booking Holdings)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$OpenTable Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenTable in 2026: restaurant plan pricing, per-cover fees, key GuestCenter features, and how it compares to Resy, Tock, and SevenRooms.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenTable is the best-known online restaurant reservation platform, connecting diners to restaurants for free while charging restaurants a subscription plus per-reservation fees. It was founded on July 2, 1998, in San Francisco by Chuck Templeton, Sid Gorham, and Eric Moe, initially incorporated as easyeats.com before rebranding to OpenTable.com in 1999. The company went public on NASDAQ under the ticker OPEN in 2009, and in 2014 was acquired by The Priceline Group (renamed Booking Holdings in 2018) for approximately $2.6 billion in cash; it now operates as a subsidiary of Booking Holdings alongside Booking.com, Priceline, Kayak, and Agoda. OpenTable connects diners to more than 60,000 restaurants worldwide and facilitates well over a billion diner visits annually through its free consumer app and website, where users can search availability, book instantly, join dining loyalty programs, and earn OpenTable Dining Points redeemable for discounts. On the restaurant side, OpenTable sells three subscription tiers: Basic at $149/month, Core at $299/month plus $1 per network cover, and Pro at $499/month plus $1 per network cover, with an additional 2% service fee introduced in early 2026 on deposits and prepaid dining experiences. Restaurant-facing tools include the GuestCenter reservation and table-management system, a guest CRM with dining history and preferences, a waitlist and walk-in management feature, POS integrations, marketing placement within OpenTable's network, and review collection. OpenTable's target customers range from independent restaurants needing basic online booking to multi-location restaurant groups and hotels needing centralized guest data across venues. Its main competitors are Resy (owned by American Express, which is merging in Tock, also Amex-owned, to reach over 25,000 combined venues), Yelp Guest Manager, SevenRooms (positioned for enterprise restaurant groups and hospitality brands), and Toast Tables. Many restaurants have publicly cited OpenTable's per-cover fees and 2026 service fee as reasons for evaluating alternatives with flatter pricing. OpenTable remains, however, the largest reservation network by sheer restaurant count and diner reach in most English-speaking markets, making network effects its biggest competitive advantage even as newer platforms compete on pricing and CRM depth.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ae9d7434-92d8-4d57-91cd-e0572dbd91d6';

