-- ── OpenTripPlanner ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenTripPlanner (OTP) is an open-source, multimodal trip-planning engine that computes public transit, walking, cycling, and driving itineraries, used by transit agencies and mobility developers worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$Open-source project maintained by a global community of transit agencies and contributors, not a single company$q$, company_size),
  headquarters = COALESCE($q$Originated at TriMet in Portland, Oregon, United States; now governed by an international Project Leadership Committee$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenTripPlanner Review 2026: Features, Deployment and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenTripPlanner in 2026: how the open-source multimodal trip-planning engine works, OTP2 routing, GTFS and NeTEx support, and deployment costs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenTripPlanner (OTP) is a free, open-source, multimodal trip-planning engine that calculates itineraries combining public transit, walking, cycling, and driving. It originated in July 2009 when Portland, Oregon's transit agency, TriMet, used a Regional Travel Options grant to host a three-day kickoff workshop bringing together transit agencies and the developers of the era's leading open-source transit routing tools, David Emory of FivePoints, Brian Ferris of OneBusAway, and Brandon Martin-Anderson of Graphserver, to build a unified successor. From 2009 through 2012, development was coordinated by the New York nonprofit OpenPlans, after which stewardship shifted to a distributed, international community of contributing transit agencies, consultancies, and individual developers organized around a Project Leadership Committee; no single company owns OTP, and governance requires changes to be reviewed and approved by contributors from at least two different organizations. OTP ingests standard transit data formats, primarily GTFS (General Transit Feed Specification) for schedules and, since the OTP2 rewrite, the EU-standard NeTEx format, plus OpenStreetMap data for the street, path, and cycling network, to compute itineraries. A major architectural overhaul, OTP2, was initiated in 2018 when the Norwegian transit organizations Ruter and Entur led the integration of a new round-based transit routing engine inspired by the R5 routing algorithm; OTP2 entered feature freeze in September 2020 and was released at the end of November 2020, delivering major performance gains and full NeTEx compatibility for European regulatory compliance. OpenTripPlanner is deployed by transit agencies and cities worldwide, from TriMet's own regional trip planner in Portland to national-level deployments in Norway (Entur), and is embedded in numerous public-facing trip-planning apps and mobility-as-a-service (MaaS) platforms. Its target audience is public transit agencies, municipal and regional transportation authorities, and mobility developers who need a self-hosted, customizable routing engine rather than a proprietary API, often for reasons of cost control, data sovereignty, or the ability to model agency-specific fare and accessibility rules. Because it is open source under the LGPL, there is no license fee; costs come from hosting, data preparation, and any commercial support or integration work purchased from firms such as Conveyal, Entur, or Cambridge Systematics. Its closest alternatives include Google's proprietary transit directions API, Conveyal's R5 engine (which influenced OTP2's routing core), Motion Tag, and Google's open GTFS ecosystem tools more broadly, though OTP remains one of the only fully open-source, self-hostable multimodal routing engines with wide agency adoption.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5f8129e3-98ab-4d78-94b2-3a35a0efb279';

