-- ── OpenTTD ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenTTD is a free, open-source business simulation game that reimplements and expands the 1995 classic Transport Tycoon Deluxe, tasking players with building rail, road, air, and sea transport networks.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$Volunteer open-source community project; no company$q$, company_size),
  headquarters = COALESCE($q$Originated in Sweden (creator Ludvig Strigeus); community-developed and distributed via openttd.org$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenTTD Review 2026: Features, Gameplay and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenTTD in 2026: how the free, open-source Transport Tycoon Deluxe remake plays, its modding ecosystem, multiplayer, and alternatives for tycoon fans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenTTD is a free, open-source business simulation video game that reverse-engineers and substantially expands Chris Sawyer's 1995 classic Transport Tycoon Deluxe. Swedish programmer Ludvig Strigeus began reverse-engineering the original game and converting it to C in 2003, contacting Owen Rudge, owner of the TT-Forums community, to share his plans; the first working release was published on March 6, 2004, under the name OpenTTD. What started as one developer's personal project quickly grew into a community-driven effort, and OpenTTD is now maintained by a large, ongoing volunteer team under the GNU General Public License version 2. In the original game, players build and operate transport networks, trains, road vehicles, ships, and aircraft, connecting cities and industries to move passengers and cargo for profit across a persistent, growing simulated economy and map. OpenTTD preserves this core gameplay loop while adding a long list of features the original never had: much larger and more varied procedurally generated maps, support for dozens of languages, custom scriptable AI opponents and game scripts, extensive mod support via the NewGRF format (custom vehicles, graphics, and scenarios), robust multiplayer over local networks or the internet, and native ports for Windows, macOS, Linux, and BSD. Because the original game's proprietary graphics and sound assets could not legally be redistributed, the community also created free replacement asset packs, OpenGFX, OpenSFX, and OpenMSX, so OpenTTD can be played entirely without owning the original commercial game. OpenTTD received recognition early on, including the most votes for Game of the Year in the 2004 Amiga Games Award, and has remained in continuous active development for over two decades, a rarity among fan remakes. It targets hobbyist strategy and simulation gamers, especially fans of classic tycoon and transport-management games, as well as modders and scripters who enjoy building custom AI opponents, scenarios, or graphics packs. Its closest peers are other classic-game remakes and successors such as Locomotion, Transport Fever, Cities: Skylines' transport-focused mods, and Simutrans, though OpenTTD is distinguished by being completely free, fully open source, cross-platform, and still actively updated by its original community more than 20 years after launch.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ae510c8a-18ad-492c-8df9-432190e35f9d';

