-- ── OpenVAS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenVAS (Open Vulnerability Assessment Scanner) is a free, open-source network vulnerability scanner that also forms the core scan engine behind Greenbone's commercial vulnerability management products.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); Greenbone Enterprise appliances at custom pricing$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$Greenbone AG: approximately 100-150 employees (small-to-medium cybersecurity company)$q$, company_size),
  headquarters = COALESCE($q$Osnabruck, Germany (Greenbone AG)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$OpenVAS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenVAS in 2026: how the open-source vulnerability scanner works, its ties to Greenbone, feed pricing tiers, and how it compares to Nessus and Qualys.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenVAS (Open Vulnerability Assessment Scanner) is a free, open-source network vulnerability scanner used to identify security weaknesses, misconfigurations, and missing patches across IT infrastructure. It originated as a fork of the Nessus scanning engine after Nessus's developer, Tenable Network Security, changed Nessus to a proprietary license in October 2005, prompting the open-source community to continue development independently under the OpenVAS name. Shortly afterward, in 2008, the German company Greenbone was founded in Osnabruck, Germany, specifically to provide professional development, support, and commercial products built around OpenVAS; Greenbone remains headquartered in Osnabruck today and has grown into a cybersecurity vendor of roughly 100 to 150 employees serving more than 100,000 installations across over 150 countries. Since 2006, OpenVAS's development has been driven primarily by Greenbone, and in 2009 the company began layering additional modules on top of the core scanner to build a full vulnerability management solution. In 2017, Greenbone rebranded the overall product family as Greenbone Vulnerability Management (GVM), with OpenVAS continuing on as the name of the free, open-source scanning engine at its core, while GVM refers to the broader open-source and commercial framework (scan management, reporting, and a web UI, the Greenbone Security Assistant) built around it. OpenVAS itself remains free and open source, testing targets against a continuously updated feed of vulnerability tests (VTs) covering thousands of CVEs, and supporting both authenticated (credentialed) and unauthenticated network scans. Greenbone monetizes through commercial offerings layered on top of the free core: OPENVAS BASIC, an entry-level licensed product aimed at small businesses (priced roughly 50 percent below comparable competitor licenses according to Greenbone), and Greenbone Enterprise appliances and enterprise feed subscriptions for larger organizations, both quoted on a custom basis rather than published at a fixed price. OpenVAS's target audience spans security teams, penetration testers, managed security service providers (MSSPs), and compliance-driven organizations that need CVE/CVSS-based vulnerability scanning without the licensing costs of proprietary scanners. Its main competitors are Tenable Nessus (the tool it originally forked from), Qualys VMDR, Rapid7 InsightVM, and Tenable.io, with OpenVAS/Greenbone's key differentiator being its open-source core, GDPR-conscious German origin, and lower-cost commercial tiers relative to those established proprietary vendors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2d037963-f9fb-4d88-bcc4-228a333d83cf';

